using System.Collections;
using System.Collections.Generic;
using UnityEngine;
using UnityEngine.InputSystem;

/// <summary>
/// Mapa-Múndi (GDD "Cérebro do Sistema"): orquestra toda a navegação do
/// Mapa-Múndi — lê o analógico esquerdo (<see cref="PlayerInputRouter.Move"/>)
/// para escolher para que <see cref="WorldMapNode"/> a <see cref="LightBallController"/>
/// deve viajar, aplica os "trechos" de câmara (<see cref="WorldMapCameraRig"/>) e
/// as transições visuais de cada <see cref="WorldMapConnection"/>, gere o
/// desbloqueio/compra de áreas (incluindo auto-desbloqueio de Vilas e a
/// sequência especial de desbloqueio do Boss) e a "Visão do Mapa-Múndi"
/// (analógico direito, <see cref="PlayerInputRouter.Look"/>).
///
/// Tudo é configurável no Inspector — este script não precisa de ser editado
/// para ajustar velocidades, zooms, custos, etc. (ver os outros componentes do
/// Mapa-Múndi: <see cref="LightBallController"/>, <see cref="WorldMapCameraRig"/>,
/// <see cref="WorldMapNode"/>, <see cref="WorldMapConnection"/>).
/// </summary>
[DisallowMultipleComponent]
public class WorldMapController : MonoBehaviour
{
    public static WorldMapController Instance { get; private set; }

    [Header("Referências — Jogador / Input")]
    [Tooltip("Router de input do jogador. O analógico esquerdo (Move) navega pelos ramos; o analógico direito (Look) activa a Visão do Mapa-Múndi (se desbloqueada).")]
    public PlayerInputRouter inputRouter;

    [Tooltip("Acção de Confirmar (ex: botão A/Sul) — desbloqueia a área alcançável actual (gastando Runas de Gaia, se aplicável) ou, se já desbloqueada, pede para viajar até lá. Atribuir no Inspector a partir do Input Actions Asset do projecto.")]
    public InputActionReference confirmAction;

    [Tooltip("Acção de Cancelar (ex: botão B/Leste) — fecha o Mapa-Múndi e devolve o jogador à área de onde saiu. WorldMapEntryPoint subscreve CancelRequested para isto.")]
    public InputActionReference cancelAction;

    [Header("Referências — Cena do Mapa")]
    public LightBallController ball;
    public WorldMapCameraRig cameraRig;
    public WorldMapUI ui;

    [Tooltip("O nó do Coração de Gaia (centro do mapa, hub para os 6 mundos). Obrigatório.")]
    public WorldMapNode gaiaHubNode;

    [Tooltip("Todos os nós do Mapa-Múndi presentes na cena. Se ficar vazio, em Awake são recolhidos automaticamente todos os WorldMapNode da cena (FindObjectsOfType, incluindo inactivos).")]
    public List<WorldMapNode> allNodes = new List<WorldMapNode>();

    [Header("Navegação")]
    [Tooltip("Magnitude mínima do analógico esquerdo/direito para ser considerada um input de navegação/observação.")]
    [Range(0.1f, 1f)]
    public float inputDeadzone = 0.5f;

    [Tooltip("Alinhamento mínimo (produto escalar entre a direcção do analógico e a direcção de um ramo, de -1 a 1) para esse ramo ser escolhido. Valores mais altos exigem apontar com mais precisão.")]
    [Range(0f, 1f)]
    public float directionThreshold = 0.5f;

    [Tooltip("Tempo (segundos) de espera depois de a bola parar num nó antes de aceitar novo input de navegação — evita disparar duas viagens com um único movimento do analógico.")]
    public float navigationCooldown = 0.25f;

    [Header("Visão do Mapa-Múndi (Upgrade)")]
    [Tooltip("Upgrade que activa a Visão do Mapa-Múndi (analógico direito observa o mundo actual sem mover a bola, revelando nomes/custos de áreas bloqueadas). Deixar vazio desactiva esta funcionalidade.")]
    public UpgradeData mapVisionUpgrade;

    [Header("Desbloqueio do Boss — Sequência de Câmara")]
    [Tooltip("Zoom (tamanho ortográfico) usado pela câmara ao focar a área do Boss durante a sequência automática de desbloqueio.")]
    public float bossUnlockOrthographicSize = 4f;

    [Tooltip("Duração (segundos) do movimento de câmara até à área do Boss e do regresso ao nó actual.")]
    public float bossUnlockCameraTravelDuration = 1.5f;

    [Tooltip("Tempo (segundos) que a câmara permanece focada na área do Boss antes de regressar — usar para sincronizar com partículas/animações próprias da área (configuradas nos objectos da cena).")]
    public float bossUnlockAnimationDuration = 1.5f;

    [Header("Área Secreta de Apolo")]
    [Tooltip("Nó do Mapa-Múndi correspondente à área secreta de Apolo (deve ter AreaData = EmblemManager.apoloSecretArea). Quando o Emblema de Apolo for obtido, a câmara viaja até este nó e a área fica desbloqueada.")]
    public WorldMapNode apoloSecretNode;

    [Tooltip("EmblemData do Emblema de Apolo — usado para verificar se o emblema foi obtido (EmblemData.obtainedVariable em GameVariables) antes de reproduzir a sequência de desbloqueio.")]
    public EmblemData apoloEmblemData;

    [Tooltip("Duração (segundos) em que a câmara permanece focada na área secreta de Apolo antes de regressar — usar para sincronizar com partículas/animações configuradas na cena.")]
    public float apoloUnlockAnimationDuration = 2f;

    [Header("Transição Visual entre Regiões")]
    [Tooltip("Sistema de partículas de chuva. A taxa de emissão (rateOverTime) é interpolada entre 0 e 'maxRainEmissionRate' segundo o 'rainIntensity' dos RegionVisualKeyframe activos.")]
    public ParticleSystem rainParticles;
    [Tooltip("Taxa de emissão (partículas/segundo) quando 'rainIntensity' = 1.")]
    public float maxRainEmissionRate = 50f;

    [Tooltip("Sistema de partículas de neve — funciona como 'rainParticles', usando 'snowIntensity'.")]
    public ParticleSystem snowParticles;
    public float maxSnowEmissionRate = 50f;

    [Tooltip("Sistema de partículas ambiente/decorativas (pólen, vagalumes, fuligem, etc.) — funciona como 'rainParticles', usando 'ambientParticlesIntensity'.")]
    public ParticleSystem ambientParticles;
    public float maxAmbientEmissionRate = 20f;

    [Tooltip("Se activo, aplica 'ambientColor'/'ambientIntensity'/'fogColor'/'fogDensity' dos RegionVisualKeyframe directamente a RenderSettings (luz ambiente e neblina globais da cena do Mapa-Múndi).")]
    public bool applyToRenderSettings = true;

    // -------------------- Estado --------------------

    /// <summary>Nó onde a bola está parada (válido sempre que a bola não estiver em movimento).</summary>
    public WorldMapNode CurrentNode { get; private set; }

    /// <summary>Mundo em que o jogador está actualmente (null no Coração de Gaia).</summary>
    public WorldData CurrentWorldContext { get; private set; }

    /// <summary>Enquanto verdadeiro, ignora todo o input de navegação/confirmação/cancelamento — usado durante a sequência de desbloqueio do Boss e a apresentação do mundo (WorldMapUI).</summary>
    public bool ControlsLocked { get; private set; }

    /// <summary>Bloqueia/desbloqueia manualmente o input do Mapa-Múndi — usado por WorldMapUI durante a apresentação do mundo (1ª vez).</summary>
    public void SetControlsLocked(bool locked) => ControlsLocked = locked;

    /// <summary>Disparado quando o jogador confirma "Viajar" numa área já desbloqueada. WorldMapEntryPoint deve fechar o Mapa-Múndi e carregar esta área.</summary>
    public event System.Action<AreaData> TravelRequested;

    /// <summary>Disparado quando o jogador pressiona Cancelar — WorldMapEntryPoint deve fechar o Mapa-Múndi e devolver o jogador à área de onde saiu.</summary>
    public event System.Action CancelRequested;

    private float navCooldownTimer;
    private bool started;

    // ==================================================================
    // Ciclo de Vida
    // ==================================================================

    private void Awake()
    {
        if (Instance != null && Instance != this) { Destroy(gameObject); return; }
        Instance = this;

        if (allNodes == null || allNodes.Count == 0)
            allNodes = new List<WorldMapNode>(FindObjectsOfType<WorldMapNode>(true));
    }

    private void OnEnable()
    {
        if (confirmAction != null) { confirmAction.action.Enable(); confirmAction.action.performed += OnConfirmPerformed; }
        if (cancelAction != null) { cancelAction.action.Enable(); cancelAction.action.performed += OnCancelPerformed; }

        if (ball != null)
        {
            ball.ArrivedAtNode += OnBallArrived;
            ball.ProgressChanged += OnBallProgressChanged;
        }
    }

    private void OnDisable()
    {
        if (confirmAction != null) confirmAction.action.performed -= OnConfirmPerformed;
        if (cancelAction != null) cancelAction.action.performed -= OnCancelPerformed;

        if (ball != null)
        {
            ball.ArrivedAtNode -= OnBallArrived;
            ball.ProgressChanged -= OnBallProgressChanged;
        }
    }

    private void Start()
    {
        RefreshAllNodeVisuals();
        WarpToCurrentArea();
        started = true;

        CheckBossUnlocks();
        CheckApoloAreaUnlock();
    }

    private void Update()
    {
        if (ControlsLocked || ball == null || CurrentNode == null) return;

        if (cameraRig.IsFreeLooking)
        {
            HandleFreeLook();
            return;
        }

        if (ball.IsMoving) return;

        if (navCooldownTimer > 0f)
        {
            navCooldownTimer -= Time.deltaTime;
            return;
        }

        HandleMapVisionToggle();
        if (cameraRig.IsFreeLooking) return;

        HandleNavigationInput();
    }

    // ==================================================================
    // Posicionamento Inicial
    // ==================================================================

    /// <summary>Posiciona a bola no nó correspondente à área actual do jogador (WorldState.CurrentArea), ou no Coração de Gaia se não encontrar correspondência.</summary>
    public void WarpToCurrentArea()
    {
        WorldMapNode target = gaiaHubNode;

        var currentArea = WorldState.Instance != null ? WorldState.Instance.CurrentArea : null;
        if (currentArea != null)
        {
            var node = FindNodeForArea(currentArea);
            if (node != null) target = node;
        }

        if (ball != null && target != null)
            ball.WarpToNode(target);
    }

    private WorldMapNode FindNodeForArea(AreaData area)
    {
        if (area == null) return null;

        foreach (var node in allNodes)
            if (node != null && node.area == area) return node;

        return null;
    }

    // ==================================================================
    // Chegada a um Nó / Câmara / Transições Visuais
    // ==================================================================

    private void OnBallArrived(WorldMapNode node)
    {
        CurrentNode = node;
        cameraRig.ResetShotTracking();

        if (node.isGaiaHub)
        {
            CurrentWorldContext = null;
            cameraRig.ShowGaiaHub();
            if (ui != null) ui.ShowGaiaHubHud(this);
        }
        else
        {
            CurrentWorldContext = node.area != null ? node.area.world : null;
            cameraRig.FocusNode(node);

            bool isWorldEntryNode = node.parentConnection != null
                                    && node.parentConnection.fromNode != null
                                    && node.parentConnection.fromNode.isGaiaHub;

            var pp = PlayerProgress.Instance;

            if (isWorldEntryNode && CurrentWorldContext != null && pp != null && node.area != null && !pp.HasVisited(node.area) && ui != null)
                ui.ShowWorldPresentation(CurrentWorldContext);

            if (pp != null && node.area != null) pp.MarkVisited(node.area);

            if (ui != null) ui.ShowWorldHud(CurrentWorldContext);
        }

        if (ui != null) ui.ShowPanelForNode(node);

        if (started) CheckBossUnlocks();
        if (started) CheckApoloAreaUnlock();
    }

    private void OnBallProgressChanged(WorldMapConnection connection, float progress)
    {
        cameraRig.FollowConnectionProgress(connection, progress);
        ApplyVisualKeyframes(connection, progress);
    }

    /// <summary>
    /// Interpola os <see cref="RegionVisualKeyframe"/> de "connection" segundo
    /// "progress" e aplica o resultado a RenderSettings (luz ambiente/neblina) e
    /// aos sistemas de partículas de chuva/neve/ambiente configurados acima.
    /// Não exige que a lista esteja ordenada por progresso.
    /// </summary>
    private void ApplyVisualKeyframes(WorldMapConnection connection, float progress)
    {
        var keys = connection != null ? connection.visualKeyframes : null;
        if (keys == null || keys.Count == 0) return;

        RegionVisualKeyframe a = null;
        RegionVisualKeyframe b = null;

        foreach (var k in keys)
        {
            if (k.progress <= progress && (a == null || k.progress > a.progress)) a = k;
            if (k.progress > progress && (b == null || k.progress < b.progress)) b = k;
        }

        if (a == null) a = b;
        if (b == null) b = a;
        if (a == null) return;

        float localT = 0f;
        if (a != b)
        {
            float range = b.progress - a.progress;
            localT = range > 0f ? Mathf.Clamp01((progress - a.progress) / range) : 0f;
        }

        Color ambientColor = Color.Lerp(a.ambientColor, b.ambientColor, localT);
        float ambientIntensity = Mathf.Lerp(a.ambientIntensity, b.ambientIntensity, localT);
        float fogDensity = Mathf.Lerp(a.fogDensity, b.fogDensity, localT);
        Color fogColor = Color.Lerp(a.fogColor, b.fogColor, localT);
        float rain = Mathf.Lerp(a.rainIntensity, b.rainIntensity, localT);
        float snow = Mathf.Lerp(a.snowIntensity, b.snowIntensity, localT);
        float ambientParticlesT = Mathf.Lerp(a.ambientParticlesIntensity, b.ambientParticlesIntensity, localT);

        if (applyToRenderSettings)
        {
            RenderSettings.ambientLight = ambientColor * ambientIntensity;
            RenderSettings.fogColor = fogColor;
            RenderSettings.fogDensity = fogDensity;
            RenderSettings.fog = fogDensity > 0f;
        }

        SetParticleRate(rainParticles, rain * maxRainEmissionRate);
        SetParticleRate(snowParticles, snow * maxSnowEmissionRate);
        SetParticleRate(ambientParticles, ambientParticlesT * maxAmbientEmissionRate);
    }

    private static void SetParticleRate(ParticleSystem ps, float rate)
    {
        if (ps == null) return;

        var emission = ps.emission;
        emission.rateOverTime = rate;

        if (rate > 0f && !ps.isPlaying) ps.Play();
        else if (rate <= 0f && ps.isPlaying) ps.Stop();
    }

    // ==================================================================
    // Navegação (Analógico Esquerdo)
    // ==================================================================

    private void HandleNavigationInput()
    {
        if (inputRouter == null) return;

        Vector2 move = inputRouter.Move;
        if (move.magnitude < inputDeadzone) return;

        if (!FindBestDirection(move, out var connection, out var targetNode, out bool isForward)) return;

        if (isForward && !targetNode.IsReachable) return;

        StartTravel(connection, targetNode);
    }

    /// <summary>
    /// Escolhe, entre o ramo-pai (de volta a Gaia) e os ramos-filhos deste nó,
    /// aquele cuja direcção melhor se alinha com "input". Devolve false se
    /// nenhuma direcção atingir 'directionThreshold'.
    /// </summary>
    private bool FindBestDirection(Vector2 input, out WorldMapConnection connection, out WorldMapNode targetNode, out bool isForward)
    {
        connection = null;
        targetNode = null;
        isForward = true;

        Vector2 dir = input.normalized;
        float bestDot = directionThreshold;

        if (CurrentNode.parentConnection != null && CurrentNode.parentConnection.fromNode != null)
        {
            var other = CurrentNode.parentConnection.fromNode;
            Vector2 toOther = (Vector2)(other.transform.position - CurrentNode.transform.position);

            if (toOther.sqrMagnitude > 0.0001f)
            {
                float dot = Vector2.Dot(dir, toOther.normalized);
                if (dot > bestDot)
                {
                    bestDot = dot;
                    connection = CurrentNode.parentConnection;
                    targetNode = other;
                    isForward = false;
                }
            }
        }

        if (CurrentNode.childConnections != null)
        {
            foreach (var conn in CurrentNode.childConnections)
            {
                if (conn == null || conn.toNode == null) continue;

                Vector2 toOther = (Vector2)(conn.toNode.transform.position - CurrentNode.transform.position);
                if (toOther.sqrMagnitude < 0.0001f) continue;

                float dot = Vector2.Dot(dir, toOther.normalized);
                if (dot > bestDot)
                {
                    bestDot = dot;
                    connection = conn;
                    targetNode = conn.toNode;
                    isForward = true;
                }
            }
        }

        return connection != null;
    }

    private void StartTravel(WorldMapConnection connection, WorldMapNode targetNode)
    {
        navCooldownTimer = navigationCooldown;
        cameraRig.ResetShotTracking();

        if (ui != null) ui.HidePanel();

        ball.TravelAlong(connection, targetNode);
    }

    // ==================================================================
    // Confirmar / Cancelar
    // ==================================================================

    private void OnConfirmPerformed(InputAction.CallbackContext ctx)
    {
        if (ControlsLocked || ball == null || ball.IsMoving || cameraRig.IsFreeLooking || CurrentNode == null) return;
        if (CurrentNode.isGaiaHub || CurrentNode.area == null) return;

        if (!CurrentNode.IsUnlocked)
        {
            if (!CurrentNode.IsReachable) return;

            var pp = PlayerProgress.Instance;
            if (pp != null && pp.TryUnlockArea(CurrentNode.area))
            {
                AutoUnlockVillageChildren(CurrentNode);
                RefreshAllNodeVisuals();
                if (ui != null) ui.RefreshPanel();
            }

            return;
        }

        TravelRequested?.Invoke(CurrentNode.area);
    }

    private void OnCancelPerformed(InputAction.CallbackContext ctx)
    {
        if (ControlsLocked) return;
        CancelRequested?.Invoke();
    }

    /// <summary>
    /// Vilas (GDD: custo 0, auto-desbloqueadas) — sempre que uma área é
    /// desbloqueada, percorre recursivamente os seus ramos-filhos e desbloqueia
    /// automaticamente todos os que forem Vilas ainda não desbloqueadas (e os
    /// filhos dessas Vilas, em cadeia).
    /// </summary>
    private void AutoUnlockVillageChildren(WorldMapNode node)
    {
        if (node == null || node.childConnections == null) return;

        var pp = PlayerProgress.Instance;
        if (pp == null) return;

        foreach (var conn in node.childConnections)
        {
            var child = conn != null ? conn.toNode : null;
            if (child == null || child.area == null) continue;

            if (child.area.mapNodeType == AreaData.MapNodeType.Vila && !pp.IsAreaUnlocked(child.area))
            {
                pp.UnlockArea(child.area);
                AutoUnlockVillageChildren(child);
            }
        }
    }

    // ==================================================================
    // Desbloqueio do Boss
    // ==================================================================

    /// <summary>
    /// Procura, entre todos os nós, uma área de Boss ainda não desbloqueada cujo
    /// 'WorldData.mainMission' já esteja concluída (MissionManager.IsMissionCompleted)
    /// e dispara a sequência de desbloqueio (uma de cada vez).
    /// </summary>
    public void CheckBossUnlocks()
    {
        var pp = PlayerProgress.Instance;
        if (pp == null || allNodes == null) return;

        foreach (var node in allNodes)
        {
            if (node == null || node.area == null || node.area.mapNodeType != AreaData.MapNodeType.Boss) continue;
            if (pp.IsAreaUnlocked(node.area)) continue;
            if (pp.HasPlayedBossUnlockAnimation(node.area.world)) continue;

            var world = node.area.world;
            if (world == null || world.mainMission == null) continue;

            if (MissionManager.Instance != null && MissionManager.Instance.IsMissionCompleted(world.mainMission))
            {
                StartCoroutine(PlayBossUnlockSequence(node));
                break;
            }
        }
    }

    /// <summary>
    /// Sequência única de desbloqueio do Boss (GDD): bloqueia controlos, a
    /// câmara afasta-se até à área do Boss (CameraShot dedicado, configurado em
    /// 'bossUnlockOrthographicSize'/'bossUnlockCameraTravelDuration'), aguarda
    /// 'bossUnlockAnimationDuration' (tempo para partículas/animações próprias
    /// da cena), desbloqueia a área, actualiza os visuais e regressa ao nó onde
    /// o jogador estava.
    /// </summary>
    private IEnumerator PlayBossUnlockSequence(WorldMapNode bossNode)
    {
        ControlsLocked = true;
        if (ui != null) ui.HidePanel();

        var returnNode = CurrentNode;

        cameraRig.FocusNode(bossNode, bossUnlockOrthographicSize, bossUnlockCameraTravelDuration);
        yield return new WaitForSeconds(bossUnlockCameraTravelDuration);

        if (bossUnlockAnimationDuration > 0f)
            yield return new WaitForSeconds(bossUnlockAnimationDuration);

        var pp = PlayerProgress.Instance;
        if (pp != null)
        {
            pp.UnlockArea(bossNode.area);
            pp.MarkBossUnlockAnimationPlayed(bossNode.area.world);
        }

        RefreshAllNodeVisuals();

        if (returnNode != null)
            cameraRig.FocusNode(returnNode, cameraRig.defaultNodeOrthographicSize, bossUnlockCameraTravelDuration);

        yield return new WaitForSeconds(bossUnlockCameraTravelDuration);

        cameraRig.ResetShotTracking();
        ControlsLocked = false;

        if (ui != null) ui.ShowPanelForNode(returnNode != null ? returnNode : CurrentNode);
    }

    // ==================================================================
    // Desbloqueio da Área Secreta de Apolo
    // ==================================================================

    /// <summary>
    /// Verifica se o Emblema de Apolo foi obtido e a área secreta ainda não teve
    /// a sua animação de desbloqueio reproduzida — se sim, lança a sequência
    /// (câmara viaja até ao nó, área fica desbloqueada visualmente, câmara volta).
    /// Seguro chamar repetidamente; a sequência só corre uma vez por save.
    /// </summary>
    public void CheckApoloAreaUnlock()
    {
        if (apoloSecretNode == null || apoloEmblemData == null) return;

        var pp = PlayerProgress.Instance;
        if (pp == null) return;
        if (pp.HasPlayedApoloAreaUnlockAnimation()) return;

        // O EmblemManager já terá chamado pp.UnlockArea(apoloSecretArea) ao
        // conceder o Emblema de Apolo — aqui basta verificar a variável global.
        var vars = GameVariables.Instance;
        if (vars == null) return;
        if (!vars.GetBool(apoloEmblemData.obtainedVariable)) return;

        // A área deve estar desbloqueada (unlock feito pelo EmblemManager).
        if (!apoloSecretNode.IsUnlocked) return;

        StartCoroutine(PlayApoloAreaUnlockSequence());
    }

    /// <summary>
    /// Sequência única de desbloqueio da área secreta de Apolo: bloqueia
    /// controlos, câmara viaja até ao nó, aguarda a animação (partículas/efeitos
    /// da cena), actualiza os visuais e regressa ao nó onde o jogador estava.
    /// </summary>
    private IEnumerator PlayApoloAreaUnlockSequence()
    {
        ControlsLocked = true;
        if (ui != null) ui.HidePanel();

        var returnNode = CurrentNode;

        cameraRig.FocusNode(apoloSecretNode, bossUnlockOrthographicSize, bossUnlockCameraTravelDuration);
        yield return new WaitForSeconds(bossUnlockCameraTravelDuration);

        if (apoloUnlockAnimationDuration > 0f)
            yield return new WaitForSeconds(apoloUnlockAnimationDuration);

        var pp = PlayerProgress.Instance;
        if (pp != null)
            pp.MarkApoloAreaUnlockAnimationPlayed();

        RefreshAllNodeVisuals();

        if (returnNode != null)
            cameraRig.FocusNode(returnNode, cameraRig.defaultNodeOrthographicSize, bossUnlockCameraTravelDuration);

        yield return new WaitForSeconds(bossUnlockCameraTravelDuration);

        cameraRig.ResetShotTracking();
        ControlsLocked = false;

        if (ui != null) ui.ShowPanelForNode(returnNode != null ? returnNode : CurrentNode);
    }

    // ==================================================================
    // Visão do Mapa-Múndi (Upgrade — Analógico Direito)
    // ==================================================================

    /// <summary>
    /// Enquanto a bola está parada (fora do Coração de Gaia) e o jogador tem o
    /// upgrade "Visão do Mapa-Múndi", mover o analógico direito entra no modo
    /// de observação livre (WorldMapCameraRig.EnterFreeLook) e revela
    /// nomes/custos das áreas do mundo actual (RefreshAllNodeVisuals com
    /// forceRevealCurrentWorld).
    /// </summary>
    private void HandleMapVisionToggle()
    {
        if (CurrentWorldContext == null) return;
        if (mapVisionUpgrade == null) return;

        var pp = PlayerProgress.Instance;
        if (pp == null || !pp.HasUpgrade(mapVisionUpgrade)) return;

        if (inputRouter != null && inputRouter.Look.magnitude >= inputDeadzone)
        {
            cameraRig.EnterFreeLook(ball.transform);
            RefreshAllNodeVisuals(forceRevealCurrentWorld: true);
        }
    }

    /// <summary>
    /// Durante a Visão do Mapa-Múndi: o analógico direito move a câmara
    /// (WorldMapCameraRig.Pan); mover o analógico esquerdo termina a observação
    /// e devolve a câmara à bola (GDD: "mover a bola com o stick esquerdo
    /// termina a observação e retorna a câmara suavemente").
    /// </summary>
    private void HandleFreeLook()
    {
        if (inputRouter == null) return;

        cameraRig.Pan(inputRouter.Look);

        if (inputRouter.Move.magnitude >= inputDeadzone)
        {
            cameraRig.ExitFreeLook(ball.transform, cameraRig.defaultNodeOrthographicSize);
            navCooldownTimer = navigationCooldown;
            RefreshAllNodeVisuals();
        }
    }

    // ==================================================================
    // Visuais
    // ==================================================================

    /// <summary>Actualiza o visual (e rótulos) de todos os nós. Se 'forceRevealCurrentWorld' estiver activo, os nós do mundo actual (CurrentWorldContext) mostram nome/custo mesmo bloqueados — usado pela Visão do Mapa-Múndi.</summary>
    public void RefreshAllNodeVisuals(bool forceRevealCurrentWorld = false)
    {
        foreach (var node in allNodes)
        {
            if (node == null) continue;

            bool forceReveal = forceRevealCurrentWorld
                                && CurrentWorldContext != null
                                && node.area != null
                                && node.area.world == CurrentWorldContext;

            node.RefreshVisual(forceReveal);
        }
    }
}
